import axios from "axios";

// URL base da API. Em desenvolvimento vem do arquivo .env (REACT_APP_API_URL).
// Se não existir, cai no padrão http://localhost:5000/api.
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:5000/api",
});

// Busca todos os projetos (com tarefas) no backend.
export async function getProjects() {
  const { data } = await api.get("/projetos");
  return data;
}

// Cria uma nova tarefa dentro de um projeto.
// Retorna a lista completa de projetos já atualizada.
export async function createTarefa(projetoId, tarefa) {
  const { data } = await api.post(`/projetos/${projetoId}/tarefas`, tarefa);
  return data;
}

// Alterna o status (Concluído <-> Em Andamento) de uma tarefa.
// Retorna a lista completa de projetos já atualizada.
export async function toggleTarefaStatus(projetoId, tarefaId) {
  const { data } = await api.patch(`/projetos/${projetoId}/tarefas/${tarefaId}/toggle`);
  return data;
}

// Envia uma mensagem para o assistente de IA (a chamada à Anthropic
// acontece no backend, então a chave de API nunca passa pelo navegador).
export async function sendAIMessage(system, messages) {
  const { data } = await api.post("/ai/chat", { system, messages });
  return data.reply;
}

export default api;
